import com.github.javaparser.ast.ImportDeclaration;
import com.github.javaparser.ast.Modifier;
import com.github.javaparser.ast.PackageDeclaration;
import com.github.javaparser.ast.ArrayCreationLevel;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.expr.Name;

public class StringComparisonTest {

    public static void main(String[] args) {
        testImportDeclaration();
        testModifierDeclaration();
        testPackageDeclaration();
        testArrayCreationLevel();

        System.out.println("All tests completed!");
    }

    private static void testImportDeclaration() {
        System.out.println("Testing ImportDeclaration string comparison bug...");

        // Create ImportDeclaration with string parameters
        ImportDeclaration import1 = new ImportDeclaration("java.util.List", false, false);
        ImportDeclaration import2 = new ImportDeclaration("java.util.List", false, false);

        // Test the setter methods that use identity comparison
        Name name1 = new Name("java.util.List");
        Name name2 = new Name("java.util.List");

        // This should trigger the bug when comparing identical string values
        // that are not the same object reference
        import1.setName(name1);
        import2.setName(name2);

        System.out.println("ImportDeclaration test completed.");
    }

    private static void testModifierDeclaration() {
        System.out.println("Testing Modifier string comparison bug...");

        Modifier mod1 = new Modifier(Modifier.Keyword.PUBLIC);
        Modifier mod2 = new Modifier(Modifier.Keyword.PUBLIC);

        // Test the setter method that uses identity comparison
        mod1.setKeyword(Modifier.Keyword.PUBLIC);
        mod2.setKeyword(Modifier.Keyword.PUBLIC);

        System.out.println("Modifier test completed.");
    }

    private static void testPackageDeclaration() {
        System.out.println("Testing PackageDeclaration string comparison bug...");

        PackageDeclaration pkg1 = new PackageDeclaration();
        PackageDeclaration pkg2 = new PackageDeclaration();

        Name name1 = new Name("com.example.test");
        Name name2 = new Name("com.example.test");

        // Test the setter method that uses identity comparison
        pkg1.setName(name1);
        pkg2.setName(name2);

        System.out.println("PackageDeclaration test completed.");
    }

    private static void testArrayCreationLevel() {
        System.out.println("Testing ArrayCreationLevel comparison bug...");

        ArrayCreationLevel level1 = new ArrayCreationLevel();
        ArrayCreationLevel level2 = new ArrayCreationLevel();

        // Test the setter method that uses identity comparison
        level1.setDimension(null);
        level2.setDimension(null);

        System.out.println("ArrayCreationLevel test completed.");
    }
}

