    47→public class PropertyGenerator extends NodeGenerator {
    48→
    49→    private final Map<String, PropertyMetaModel> declaredProperties = new HashMap<>();
    50→    private final Map<String, PropertyMetaModel> derivedProperties = new HashMap<>();
    51→
    52→    public PropertyGenerator(SourceRoot sourceRoot) {
