    54→    }
    55→
    56→    @Override
    57→    protected void generateNode(
    58→            BaseNodeMetaModel nodeMetaModel, CompilationUnit nodeCu, ClassOrInterfaceDeclaration nodeCoid) {
    59→        for (PropertyMetaModel property : nodeMetaModel.getDeclaredPropertyMetaModels()) {
    60→            generateGetter(nodeMetaModel, nodeCoid, property);
    61→            generateSetter(nodeMetaModel, nodeCoid, property);
    62→        }
