    95→        if (property.isRequired()) {
    96→            Class<?> type = property.getType();
    97→            if (property.isNonEmpty() && property.isSingular()) {
    98→                nodeCoid.findCompilationUnit()
    99→                        .get()
   100→                        .addImport("com.github.javaparser.utils.Utils.assertNonEmpty", true, false);
   101→                body.addStatement(f("assertNonEmpty(%s);", name));
   102→            } else if (type != boolean.class && type != int.class) {
   103→                nodeCoid.findCompilationUnit()
   104→                        .get()
   105→                        .addImport("com.github.javaparser.utils.Utils.assertNotNull", true, false);
   106→                body.addStatement(f("assertNotNull(%s);", name));
   107→            }
   108→        }
