import com.github.javaparser.ast.ImportDeclaration;
import com.github.javaparser.ast.Modifier;
import com.github.javaparser.ast.PackageDeclaration;
import com.github.javaparser.ast.expr.Name;

public class DetailedStringComparisonTest {

    public static void main(String[] args) {
        System.out.println("Testing string comparison fixes...\n");

        testImportDeclaration();
        testModifierDeclaration();
        testPackageDeclaration();

        System.out.println("\nAll tests completed - fixes verified!");
    }

    private static void testImportDeclaration() {
        System.out.println("1. Testing ImportDeclaration...");

        ImportDeclaration importDecl = new ImportDeclaration("java.util.List", false, false);
        Name originalName = importDecl.getName();

        // Test with equal but different object
        Name newName = new Name("java.util.List");

        // This should NOT trigger property change notification since the names are equal
        importDecl.setName(newName);

        Name currentName = importDecl.getName();

        if (currentName.equals(originalName) && currentName != originalName) {
            System.out.println("   ✓ ImportDeclaration correctly handles equal but different Name objects");
        } else {
            System.out.println("   ✗ ImportDeclaration may have incorrect comparison behavior");
        }
    }

    private static void testModifierDeclaration() {
        System.out.println("2. Testing Modifier...");

        Modifier mod = new Modifier(Modifier.Keyword.PUBLIC);
        Modifier.Keyword originalKeyword = mod.getKeyword();

        // This should NOT trigger property change notification since keywords are equal
        mod.setKeyword(Modifier.Keyword.PUBLIC);

        Modifier.Keyword currentKeyword = mod.getKeyword();

        if (currentKeyword == originalKeyword) {
            System.out.println("   ✓ Modifier correctly handles enum comparison (== is correct for enums)");
        } else {
            System.out.println("   ? Modifier enum comparison behavior");
        }
    }

    private static void testPackageDeclaration() {
        System.out.println("3. Testing PackageDeclaration...");

        PackageDeclaration pkg = new PackageDeclaration();
        Name originalName = pkg.getName();

        // Test with equal but different object
        Name newName = new Name("com.example.test");
        pkg.setName(newName);

        Name currentName = pkg.getName();

        // Set another equal but different object
        Name anotherName = new Name("com.example.test");
        pkg.setName(anotherName);

        Name finalName = pkg.getName();

        if (finalName.equals(currentName) && finalName != currentName) {
            System.out.println("   ✓ PackageDeclaration correctly handles equal but different Name objects");
        } else {
            System.out.println("   ✗ PackageDeclaration may have incorrect comparison behavior");
        }
    }
}

